use fastmcp_server::{Server, ServerBuilder};
use fastmcp_transport::MemoryTransport;

#[tokio::test]
async fn test_as_proxy_discovers_tools() {
    // Create external server
    let external = ServerBuilder::new("external", "1.0")
        .tool(echo_tool())
        .tool(add_tool())
        .build();

    // Create transport pair
    let (client_transport, server_transport) = MemoryTransport::pair();

    // Run external server
    tokio::spawn(async move {
        external.run(server_transport).await.unwrap();
    });

    // Create main server with proxy
    let main = ServerBuilder::new("main", "1.0")
        .as_proxy("ext", client_transport)
        .await
